import{_ as a,a as e}from"./chunks/查询额度成功.wz9SQqrH.js";import{_ as d,o,c as l,a2 as s}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"pCloud Channel சேர்க்கவும்","description":"","frontmatter":{},"headers":[],"relativePath":"ta/upload/pcloud.md","filePath":"ta/upload/pcloud.md","lastUpdated":1781962217000}'),n={name:"ta/upload/pcloud.md"};function i(c,t,p,r,u,h){return o(),l("div",null,[...t[0]||(t[0]=[s('<h1 id="pcloud-channel-சேர்க்கவும்" tabindex="-1">pCloud Channel சேர்க்கவும் <a class="header-anchor" href="#pcloud-channel-சேர்க்கவும்" aria-label="Permalink to &quot;pCloud Channel சேர்க்கவும்&quot;">​</a></h1><h2 id="எப்போது-பொருத்தம்" tabindex="-1">எப்போது பொருத்தம் <a class="header-anchor" href="#எப்போது-பொருத்தம்" aria-label="Permalink to &quot;எப்போது பொருத்தம்&quot;">​</a></h2><ul><li>உங்களிடம் pCloud account உள்ளது; ImgBed images-ஐ pCloud-ல் சேமிக்க வேண்டும்.</li><li>pCloud account email மற்றும் password-ஐ channel credentials ஆக பயன்படுத்துவது உங்களுக்கு ஏற்றதாக இருந்தால்.</li></ul><h2 id="முதலில்-தேவையானவை" tabindex="-1">முதலில் தேவையானவை <a class="header-anchor" href="#முதலில்-தேவையானவை" aria-label="Permalink to &quot;முதலில் தேவையானவை&quot;">​</a></h2><table tabindex="0"><thead><tr><th>தேவை</th><th>ஏன் தேவை</th></tr></thead><tbody><tr><td>pCloud account email</td><td>pCloud API-க்கு sign in செய்ய</td></tr><tr><td>pCloud password</td><td>pCloud API-க்கு sign in செய்ய</td></tr><tr><td>API host</td><td>default <code>api.pcloud.com</code>. EU accounts <code>eapi.pcloud.com</code> பயன்படுத்தலாம்.</td></tr><tr><td>Storage directory</td><td>files சேமிக்கப்படும் இடம். default <code>imgbed</code>.</td></tr></tbody></table><h2 id="எங்கு-சேர்ப்பது" tabindex="-1">எங்கு சேர்ப்பது <a class="header-anchor" href="#எங்கு-சேர்ப்பது" aria-label="Permalink to &quot;எங்கு சேர்ப்பது&quot;">​</a></h2><ol><li>System Settings திறக்கவும்.</li><li>Upload Settings திறக்கவும்.</li><li>மேல் வலது மூலையில் <code>Add Channel</code> கிளிக் செய்யவும்.</li><li><code>pCloud</code> தேர்வு செய்யவும்.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Purpose</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>இந்த pCloud channel-ஐ அடையாளம் காண, உதா. <code>Personal pCloud</code></td><td>Yes</td></tr><tr><td>Account email</td><td>உங்கள் pCloud login email</td><td>Yes</td></tr><tr><td>Password</td><td>உங்கள் pCloud password</td><td>Yes</td></tr><tr><td>API host</td><td>pCloud API host. default <code>api.pcloud.com</code>.</td><td>No</td></tr><tr><td>Storage directory</td><td>files சேமிக்கப்படும் directory. default <code>imgbed</code>.</td><td>No</td></tr></tbody></table><p>account region படி API host தேர்வு:</p><table tabindex="0"><thead><tr><th>Account Region</th><th>API Host</th></tr></thead><tbody><tr><td>Default / US</td><td><code>api.pcloud.com</code></td></tr><tr><td>Europe</td><td><code>eapi.pcloud.com</code></td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>Upload Settings திறக்கவும்.</li><li><code>Add Channel</code> கிளிக் செய்யவும்.</li><li><code>pCloud</code> தேர்வு செய்யவும்.</li><li>அறியக்கூடிய channel name உள்ளிடவும்.</li><li>pCloud account email உள்ளிடவும்.</li><li>pCloud password உள்ளிடவும்.</li><li>API host-ஐ <code>api.pcloud.com</code> ஆக வைத்திருக்கவும்; EU account என்றால் <code>eapi.pcloud.com</code>.</li><li>storage directory-ஐ <code>imgbed</code> ஆக வைத்திருக்கவும், அல்லது உங்கள் folder-ஐ கொடுக்கவும்.</li><li>channel save செய்யவும்.</li></ol><p><img src="'+a+'" alt="Configure channel" loading="lazy"></p><h2 id="verify-செய்வது" tabindex="-1">Verify செய்வது <a class="header-anchor" href="#verify-செய்வது" aria-label="Permalink to &quot;Verify செய்வது&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Expected Result</th></tr></thead><tbody><tr><td>Channel card</td><td>Save செய்த பிறகு pCloud channel card தெரியும்.</td></tr><tr><td>Channel switch</td><td>card switch enabled ஆக இருக்கும்.</td></tr><tr><td>Email display</td><td>card connected pCloud email காட்டும்.</td></tr><tr><td>Quota query</td><td>successful query பிறகு used மற்றும் total capacity தெரியும்.</td></tr><tr><td>Upload test</td><td>test image configured pCloud storage directory-ல் தெரியும்.</td></tr></tbody></table><p><img src="'+e+`" alt="Quota query success" loading="lazy"></p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="ஏன்-oauth2-இல்லை" tabindex="-1">ஏன் OAuth2 இல்லை? <a class="header-anchor" href="#ஏன்-oauth2-இல்லை" aria-label="Permalink to &quot;ஏன் OAuth2 இல்லை?&quot;">​</a></h3><p>pCloud OAuth2 default ஆக self-service இல்லை. அதை enable செய்ய pCloud-க்கு email செய்ய வேண்டும்.</p><p>தற்போதைய pCloud OAuth2 flow ImgBed-க்கு தேவையான short-lived upload link workflow-ஐ support செய்யவில்லை. அதனால் இந்த channel account email/password login பயன்படுத்துகிறது.</p><h3 id="எந்த-api-host-பயன்படுத்த-வேண்டும்" tabindex="-1">எந்த API Host பயன்படுத்த வேண்டும்? <a class="header-anchor" href="#எந்த-api-host-பயன்படுத்த-வேண்டும்" aria-label="Permalink to &quot;எந்த API Host பயன்படுத்த வேண்டும்?&quot;">​</a></h3><p>Default:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>api.pcloud.com</span></span></code></pre></div><p>EU accounts:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>eapi.pcloud.com</span></span></code></pre></div><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pCloud email மற்றும் password தயார் செய்யவும்</span></span>
<span class="line"><span>-&gt; Upload Settings திறக்கவும்</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; pCloud தேர்வு செய்யவும்</span></span>
<span class="line"><span>-&gt; channel name / email / password நிரப்பவும்</span></span>
<span class="line"><span>-&gt; account Europe அல்ல என்றால் API host api.pcloud.com வைத்திருக்கவும்</span></span>
<span class="line"><span>-&gt; வேறு தேவை இல்லை என்றால் storage directory imgbed வைத்திருக்கவும்</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; quota query</span></span>
<span class="line"><span>-&gt; test image upload</span></span></code></pre></div>`,28)])])}const f=d(n,[["render",i]]);export{g as __pageData,f as default};
